1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	
7	const BASE_PREMIUM: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
17	type Step = { op: "quote"; items: Item[] };
18	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
19	
20	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const BLOCK_SIZE = 3;
24	const BLOCK_BASE_PREMIUM = 60;
25	
26	const sumBasePremiums = (items: Item[]): number =>
27	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
28	
29	const componentGroupSubtotalOf = (group: Item[]): number =>
30	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
31	
32	const groupByType = (items: Item[]): Map<string, Item[]> => {
33	  const groups = new Map<string, Item[]>();
34	  for (const item of items) {
35	    const existing = groups.get(item.type) ?? [];
36	    existing.push(item);
37	    groups.set(item.type, existing);
38	  }
39	  return groups;
40	};
41	
42	const componentSubtotalOf = (components: Item[]): number =>
43	  [...groupByType(components).values()].reduce(
44	    (sum, group) => sum + componentGroupSubtotalOf(group),
45	    0,
46	  );
47	
48	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
49	
50	const policyBaseOf = (items: Item[]): number => {
51	  const components = items.filter(isComponent);
52	  const mainItems = items.filter((item) => !isComponent(item));
53	  return sumBasePremiums(mainItems) + componentSubtotalOf(components);
54	};
55	
56	const firstInsuranceSurchargeOf = (policyBase: number): number =>
57	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
58	
59	const cursedSurchargeOf = (item: Item): number =>
60	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
61	
62	const highEnchantmentSurchargeOf = (item: Item): number =>
63	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
64	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
65	    : 0;
66	
67	const itemSurchargesOf = (items: Item[]): number =>
68	  items.reduce(
69	    (sum, item) => sum + cursedSurchargeOf(item) + highEnchantmentSurchargeOf(item),
70	    0,
71	  );
72	
73	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
74	
75	const quotePremium = (items: Item[]): number => {
76	  const policyBase = policyBaseOf(items);
77	  const rawPremium =
78	    policyBase + itemSurchargesOf(items) + firstInsuranceSurchargeOf(policyBase) + PROCESSING_FEE;
79	  return roundUpInMHPCOFavor(rawPremium);
80	};
81	
82	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
83	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
84	  return { results };
85	};
